'use strict';

var _quiverStreamChannel = require('quiver-stream-channel');

var _libStreamUtil = require('../lib/stream-util');

const chai = require('chai');
const should = chai.should();

const testString = '世界你好';
const testBuffer = new Buffer(testString);
const buffer1 = testBuffer.slice(0, 5);
const buffer2 = testBuffer.slice(5, 10);
const buffer3 = testBuffer.slice(10, 12);

describe('unicode text test', function () {
  it('buffer to string then concat should not equal original', function () {
    const result = '' + buffer1 + '' + buffer2 + '' + buffer3;
    result.should.not.equal(testString);
  });

  it('buffer concat then to string should equal original', function () {
    const buffer = Buffer.concat([buffer1, buffer2, buffer3]);
    const result = '' + buffer;
    result.should.equal(testString);
  });

  it('stream to text should equal original', function () {
    var _createChannel = (0, _quiverStreamChannel.createChannel)();

    const readStream = _createChannel.readStream;
    const writeStream = _createChannel.writeStream;

    writeStream.write(buffer1);
    writeStream.write(buffer2);
    writeStream.write(buffer3);
    writeStream.closeWrite();

    return (0, _libStreamUtil.streamToText)(readStream).then(function (text) {
      return text.should.equal(testString);
    });
  });
});